async function getEmbedding(text) {
  const cfgResp = await helpers.httpRequest({ method: 'GET', url: '{{SUPABASE_URL}}/rest/v1/tools_config?tool_name=eq.embedding&select=config,enabled', headers: { 'apikey': '{{SUPABASE_SERVICE_KEY}}', 'Content-Type': 'application/json' } });
  const cfg = (Array.isArray(cfgResp) && cfgResp.length > 0 && cfgResp[0].enabled) ? cfgResp[0].config : null;
  if (!cfg || !cfg.api_key) return null;
  const provider = cfg.provider || 'openai';
  const apiKey = cfg.api_key;
  const model = cfg.model || 'text-embedding-3-small';
  try {
    if (provider === 'openai') {
      const res = await helpers.httpRequest({ method: 'POST', url: 'https://api.openai.com/v1/embeddings', headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' }, body: JSON.stringify({ model, input: text }) });
      return res.data[0].embedding;
    }
    if (provider === 'voyage') {
      const res = await helpers.httpRequest({ method: 'POST', url: 'https://api.voyageai.com/v1/embeddings', headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' }, body: JSON.stringify({ model: model || 'voyage-3-lite', input: [text] }) });
      return res.data[0].embedding;
    }
    if (provider === 'ollama') {
      const ollamaUrl = cfg.ollama_url || 'http://localhost:11434';
      const res = await helpers.httpRequest({ method: 'POST', url: `${ollamaUrl}/api/embed`, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ model: model || 'nomic-embed-text', input: text }) });
      return res.embeddings[0];
    }
  } catch(e) { return null; }
  return null;
}

const sessionId = $('Build System Prompt').first().json.sessionId || '';
let input;
try { input = JSON.parse(query); } catch(e) { input = {}; }
const id = input.id;
if (!id) return JSON.stringify({ error: 'id is required. Use memory_search first to find the ID.' });
if (!sessionId) return JSON.stringify({ error: 'sessionId missing from context — cannot enforce user scope.' });
const patch = {};
if (input.content) patch.content = input.content;
if (input.category) patch.category = input.category;
if (input.importance) patch.importance = input.importance;
if (input.tags) patch.tags = Array.isArray(input.tags) ? input.tags.map(t => String(t).toLowerCase()) : input.tags;
if (input.entity_name) patch.entity_name = input.entity_name;
if (input.source) patch.source = input.source;
if (Object.keys(patch).length === 0) return JSON.stringify({ error: 'Provide at least one field to update: content, category, importance, tags, entity_name, or source.' });
if (input.content) {
  const embedding = await getEmbedding(input.content);
  if (embedding) patch.embedding = JSON.stringify(embedding);
}
const scopeFilter = `or=(user_id.is.null,user_id.eq.${encodeURIComponent(sessionId)})`;
const result = await helpers.httpRequest({
  method: 'PATCH',
  url: `{{SUPABASE_URL}}/rest/v1/memory_long?id=eq.${id}&${scopeFilter}`,
  headers: {
    'apikey': '{{SUPABASE_SERVICE_KEY}}',
    'Content-Type': 'application/json',
    'Prefer': 'return=representation'
  },
  body: JSON.stringify(patch),
  returnFullResponse: true
});
const body = result.body;
if (Array.isArray(body) && body.length === 0) return JSON.stringify({ error: `Memory with id ${id} not found or not owned by this user.` });
return JSON.stringify({ success: true, updated_id: id, fields: Object.keys(patch).filter(k => k !== 'embedding'), vectorized: !!patch.embedding });

let input;
try { input = JSON.parse(query); } catch(e) { input = {url: query}; }
if (!input.url) return 'Fehler: url ist Pflicht';
const opts = {
