  } catch(e) {
    return 'Parse error: query=' + String(query).substring(0,200) + ' type=' + qType;
  }
} else {
  return 'Unexpected query type: ' + qType + ' value: ' + String(query).substring(0,200);
}

if (typeof args === 'string') try { args = JSON.parse(args); } catch(e) {}
if (!mcpUrl || !toolName) return 'Fehler: mcp_url=' + mcpUrl + ' tool_name=' + toolName + ' (query type was: ' + qType + ')';

function parseSSE(raw) {
  const str = String(raw);
  let lines = str.split('\n');
  if (lines.length <= 1) lines = str.split('\\n');
  for (let i = lines.length - 1; i >= 0; i--) {
    const line = lines[i].trim();
    if (line.startsWith('data: ')) {
      return JSON.parse(line.substring(6));
    }
  }
  return null;
}

try {
  let authHeader = null;
  try {
    const row = await helpers.httpRequest({method:'GET',url:'{{SUPABASE_URL}}/rest/v1/mcp_registry?mcp_url=eq.'+encodeURIComponent(mcpUrl)+'&select=auth_type,auth_token&limit=1',headers:{apikey:'{{SUPABASE_SERVICE_KEY}}',Authorization:'Bearer {{SUPABASE_SERVICE_KEY}}'},json:true});
    if (row && row[0] && row[0].auth_type && row[0].auth_type !== 'none' && row[0].auth_token) {
      authHeader = row[0].auth_type === 'bearer' ? 'Bearer '+row[0].auth_token : row[0].auth_token;
    }
  } catch(e) {}

  const hdrs = {'Content-Type':'application/json','Accept':'application/json, text/event-stream'};
  if (authHeader) hdrs['Authorization'] = authHeader;

  // 1. Initialize
  const init = await helpers.httpRequest({
    method: 'POST', url: mcpUrl,
    headers: hdrs,
    body: JSON.stringify({jsonrpc:'2.0',id:1,method:'initialize',params:{protocolVersion:'2024-11-05',capabilities:{},clientInfo:{name:'n8n-claw-mcp',version:'1.0'}}}),
    returnFullResponse: true, encoding: 'utf-8', json: false
  });
  const sid = init.headers && init.headers['mcp-session-id'];
  if (sid) hdrs['mcp-session-id'] = sid;

  // 2. Initialized notification
  await helpers.httpRequest({
    method: 'POST', url: mcpUrl,
    headers: hdrs,
    body: JSON.stringify({jsonrpc:'2.0',method:'notifications/initialized'}),
    json: false
  });

  // 3. List tools to get schemas (auto-fill missing required params)
  const listResp = await helpers.httpRequest({
    method: 'POST', url: mcpUrl,
    headers: hdrs,
    body: JSON.stringify({jsonrpc:'2.0',id:2,method:'tools/list',params:{}}),
    json: false
  });
  const listResult = parseSSE(listResp);
  let toolSchema = null;
  if (listResult && listResult.result && listResult.result.tools) {
    const tool = listResult.result.tools.find(t => t.name === toolName);
    if (tool && tool.inputSchema) toolSchema = tool.inputSchema;
  }

  function schemaHint(problem) {
    if (!toolSchema) return null;
    return 'Tool "' + toolName + '" call rejected: ' + problem +
      '\n\nCorrect input schema:\n' + JSON.stringify(toolSchema, null, 2) +
      '\n\nRetry the tool call with parameter names matching this schema exactly.';
  }

  if (toolSchema && toolSchema.properties) {
    const allowed = Object.keys(toolSchema.properties);
    const required = toolSchema.required || [];
    const unknown = Object.keys(args).filter(k => !allowed.includes(k));
    const missing = required.filter(r => args[r] === undefined || args[r] === null || args[r] === '');
    if (unknown.length > 0 || missing.length > 0) {
      const problems = [];
      if (unknown.length > 0) problems.push('unknown args [' + unknown.join(', ') + ']');
      if (missing.length > 0) problems.push('missing required args [' + missing.join(', ') + ']');
      return schemaHint(problems.join('; '));
    }
  }

  const resp = await helpers.httpRequest({
    method: 'POST', url: mcpUrl,
    headers: hdrs,
    body: JSON.stringify({jsonrpc:'2.0',id:3,method:'tools/call',params:{name:toolName,arguments:args}}),
    returnFullResponse: true, encoding: 'utf-8', json: false
  });

  const result = parseSSE(resp.body || resp);
  if (!result) return String(resp.body || resp);
  if (result.error) {
    return schemaHint('server error: ' + JSON.stringify(result.error)) || ('MCP Error: ' + JSON.stringify(result.error));
  }
  if (result.result && result.result.isError) {
    const errText = (result.result.content && result.result.content[0] && result.result.content[0].text) || JSON.stringify(result.result);
    return schemaHint('tool returned error: ' + errText) || ('MCP Tool Error: ' + errText);
  }
  return result.result?.content?.[0]?.text || JSON.stringify(result.result);
} catch(e) {
  return 'MCP Error: ' + e.message;
}

parameters.description:
Manage tasks. Input: JSON with action and parameters.

Actions:
- list: List tasks. Optional: status (pending/in_progress/done/cancelled), priority, due_before (ISO date)
- create: Create task. Required: title. Optional: description, priority (low/medium/high/urgent), due_date (ISO 8601), parent_id (for subtasks), tags (array)
- update: Update task. Required: id. Optional: title, description, status, priority, due_date, tags
- delete: Delete task. Required: id
- summary: Overview of all pending/in_progress tasks grouped by priority
- set_preference: Save user preference. Required: key, value. Example: {"action":"set_preference","key":"morning_briefing","value":{"enabled":true,"time":"08:00"}}

Examples:
{"action":"create","title":"Call dentist","due_date":"2026-03-10T10:00:00+01:00","priority":"high"}
{"action":"list","status":"pending"}
{"action":"update","id":5,"status":"done"}
{"action":"summary"}

