const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';

// Multi-user scope: sessionId from Build System Prompt
const sessionId = $('Build System Prompt').first().json.sessionId || '';
if (!sessionId) return JSON.stringify({ error: 'sessionId missing from context \u2014 cannot enforce user scope.' });
const scopeFilter = `or=(user_id.is.null,user_id.eq.${encodeURIComponent(sessionId)})`;

// Helper: resolve scope string to user_id value ('user' -> sessionId, 'org' -> null)
function resolveUserId(scope) {
  const s = (scope || 'user').toLowerCase();
  return s === 'org' ? null : sessionId;
}

async function pgrest(method, path, body, extraHeaders = {}) {
  const opts = {
    method,
    url: `${SUPABASE_URL}${path}`,
    headers: { 'apikey': SUPABASE_KEY, 'Content-Type': 'application/json', ...extraHeaders },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  };
  if (body) opts.body = JSON.stringify(body);
  const res = await helpers.httpRequest(opts);
  if (!res.body || res.body === '') return null;
  return typeof res.body === 'string' ? JSON.parse(res.body) : res.body;
}

// Normalize type strings: lowercase, spaces/hyphens to underscores, trim
function normalize(s) {
  if (!s) return null;
  return s.trim().toLowerCase().replace(/\u00e4/g,'ae').replace(/\u00f6/g,'oe').replace(/\u00fc/g,'ue').replace(/\u00df/g,'ss').replace(/[\s-]+/g, '_').replace(/[^a-z0-9_]/g, '');
}

async function getEmbedding(text) {
  const cfgResp = await pgrest('GET', '/rest/v1/tools_config?tool_name=eq.embedding&select=config,enabled');
  const cfg = (Array.isArray(cfgResp) && cfgResp.length > 0 && cfgResp[0].enabled) ? cfgResp[0].config : null;
  if (!cfg || !cfg.api_key) return null;
  const provider = cfg.provider || 'openai';
  const apiKey = cfg.api_key;
  const model = cfg.model || 'text-embedding-3-small';
  try {
    if (provider === 'openai') {
      const res = await helpers.httpRequest({ method: 'POST', url: 'https://api.openai.com/v1/embeddings', headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' }, body: JSON.stringify({ model, input: text }) });
      return res.data[0].embedding;
    }
    if (provider === 'voyage') {
      const res = await helpers.httpRequest({ method: 'POST', url: 'https://api.voyageai.com/v1/embeddings', headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' }, body: JSON.stringify({ model: model || 'voyage-3-lite', input: [text] }) });
      return res.data[0].embedding;
    }
    if (provider === 'ollama') {
      const ollamaUrl = cfg.ollama_url || 'http://localhost:11434';
      const res = await helpers.httpRequest({ method: 'POST', url: `${ollamaUrl}/api/embed`, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ model: model || 'nomic-embed-text', input: text }) });
      return res.embeddings[0];
    }
  } catch(e) { return null; }
  return null;
}

let input;
try { input = JSON.parse(query); } catch(e) { return 'Error: invalid JSON. Expected: {"action":"search|save|update|relate|graph|delete", ...}'; }
const action = input.action;

if (action === 'search') {
  const body = { match_count: input.limit || 10, filter_user_id: sessionId };
  if (input.query) {
    const emb = await getEmbedding(input.query);
    if (emb) { body.query_embedding = JSON.stringify(emb); body.match_threshold = 0.5; }
  }
  if (input.name) body.search_name = input.name;
  if (input.type) body.filter_type = normalize(input.type);
  const result = await pgrest('POST', '/rest/v1/rpc/search_entities', body);
  return JSON.stringify(result);

} else if (action === 'save') {
  if (!input.name) return 'Error: name is required';
  // Check if entity already exists (exact name match) within user-or-org scope
  const existing = await pgrest('GET', `/rest/v1/kg_entities?name=ilike.${encodeURIComponent(input.name)}&${scopeFilter}&select=id,name,entity_type,summary,user_id`);
  if (existing && existing.length > 0) return JSON.stringify({ exists: true, entity: existing[0], hint: 'Entity already exists. Use update to modify it.' });
  const entityType = normalize(input.entity_type);
  const entityUserId = resolveUserId(input.scope);
  const body = { name: input.name, entity_type: entityType, summary: input.summary || null, metadata: input.metadata || {}, user_id: entityUserId };
  const embText = input.name + (input.summary ? ' ' + input.summary : '');
  const emb = await getEmbedding(embText);
  if (emb) body.embedding = JSON.stringify(emb);
  const result = await pgrest('POST', '/rest/v1/kg_entities', body, { 'Prefer': 'return=representation' });
  // Return existing types (user-or-org scope) so agent stays consistent
  const types = await pgrest('GET', `/rest/v1/kg_entities?select=entity_type&entity_type=not.is.null&${scopeFilter}&order=entity_type`);
  const usedTypes = [...new Set((types || []).map(t => t.entity_type).filter(Boolean))];
  // Find existing memories about this entity (user-or-org scope)
  const relatedMemories = await pgrest('GET', `/rest/v1/memory_long?entity_name=ilike.${encodeURIComponent(input.name)}&${scopeFilter}&select=id,content,category,tags&order=importance.desc&limit=5`);
  const response = { success: true, entity: Array.isArray(result) ? result[0] : result, existing_entity_types: usedTypes };
  if (relatedMemories && relatedMemories.length > 0) response.related_memories = relatedMemories;
  return JSON.stringify(response);

} else if (action === 'update') {
  if (!input.id) return 'Error: id (UUID) is required';
  const patch = {};
  if (input.name) patch.name = input.name;
  if (input.entity_type) patch.entity_type = normalize(input.entity_type);
  if (input.summary !== undefined) patch.summary = input.summary;
  if (input.metadata) patch.metadata = input.metadata;
  if (input.scope) patch.user_id = resolveUserId(input.scope);
  if (Object.keys(patch).length === 0) return 'Error: provide at least one field to update';
  // Fetch current row (scoped)
  if (input.name || input.summary) {
    const current = await pgrest('GET', `/rest/v1/kg_entities?id=eq.${input.id}&${scopeFilter}&select=name,summary`);
    if (!Array.isArray(current) || current.length === 0) return JSON.stringify({ error: `Entity ${input.id} not found or not owned by this user.` });
    const e = current[0];
    const embText = (patch.name || e.name) + ' ' + (patch.summary || e.summary || '');
    const emb = await getEmbedding(embText);
    if (emb) patch.embedding = JSON.stringify(emb);
  }
  patch.updated_at = new Date().toISOString();
  const result = await pgrest('PATCH', `/rest/v1/kg_entities?id=eq.${input.id}&${scopeFilter}`, patch, { 'Prefer': 'return=representation' });
  if (Array.isArray(result) && result.length === 0) return JSON.stringify({ error: `Entity ${input.id} not found or not owned by this user.` });
  return JSON.stringify({ success: true, entity: Array.isArray(result) ? result[0] : result });

} else if (action === 'relate') {
  if (!input.source_name || !input.target_name || !input.relation_type) return 'Error: source_name, target_name, and relation_type are required';
  const relType = normalize(input.relation_type);
  // Resolve names to IDs within user-or-org scope (prevents cross-user traversal)
  const srcList = await pgrest('GET', `/rest/v1/kg_entities?name=ilike.${encodeURIComponent(input.source_name)}&${scopeFilter}&select=id,name`);
  const tgtList = await pgrest('GET', `/rest/v1/kg_entities?name=ilike.${encodeURIComponent(input.target_name)}&${scopeFilter}&select=id,name`);
  if (!srcList || srcList.length === 0) return `Error: entity "${input.source_name}" not found. Save it first with action "save".`;
  if (!tgtList || tgtList.length === 0) return `Error: entity "${input.target_name}" not found. Save it first with action "save".`;
  // Check for duplicate relation
  const dupCheck = await pgrest('GET', `/rest/v1/kg_relations?source_id=eq.${srcList[0].id}&target_id=eq.${tgtList[0].id}&relation_type=eq.${encodeURIComponent(relType)}&valid_until=is.null&select=id`);
  if (dupCheck && dupCheck.length > 0) return JSON.stringify({ exists: true, relation_id: dupCheck[0].id, hint: 'This relation already exists.' });
  const body = {
    source_id: srcList[0].id,
    target_id: tgtList[0].id,
    relation_type: relType,
    weight: input.weight || 1.0,
    metadata: input.metadata || {}
  };
  if (input.valid_from) body.valid_from = input.valid_from;
  if (input.valid_until) body.valid_until = input.valid_until;
  const result = await pgrest('POST', '/rest/v1/kg_relations', body, { 'Prefer': 'return=representation' });
  // Return existing relation types (global \u2014 relation_type is not user-scoped)
  const rtypes = await pgrest('GET', '/rest/v1/kg_relations?select=relation_type&order=relation_type');
  const usedRelTypes = [...new Set((rtypes || []).map(r => r.relation_type).filter(Boolean))];
  return JSON.stringify({ success: true, relation: Array.isArray(result) ? result[0] : result, existing_relation_types: usedRelTypes });

} else if (action === 'graph') {
  if (!input.name) return 'Error: name is required';
  const entities = await pgrest('GET', `/rest/v1/kg_entities?name=ilike.${encodeURIComponent(input.name)}&${scopeFilter}&select=id,name,entity_type,summary`);
  if (!entities || entities.length === 0) return `Error: entity "${input.name}" not found`;
  const startEntity = entities[0];
  const graph = await pgrest('POST', '/rest/v1/rpc/search_entity_graph', { start_id: startEntity.id, max_depth: input.depth || 2, filter_user_id: sessionId });
  // Include related memories for the center entity (scoped)
  const memories = await pgrest('GET', `/rest/v1/memory_long?entity_name=ilike.${encodeURIComponent(input.name)}&${scopeFilter}&select=id,content,category,tags&order=importance.desc&limit=5`);
  const response = { center: startEntity, connections: graph };
  if (memories && memories.length > 0) response.related_memories = memories;
  return JSON.stringify(response);

} else if (action === 'delete') {
  if (!input.id) return 'Error: id (UUID) is required';
  const result = await pgrest('DELETE', `/rest/v1/kg_entities?id=eq.${input.id}&${scopeFilter}`, null, { 'Prefer': 'return=representation' });
  if (Array.isArray(result) && result.length === 0) return JSON.stringify({ error: `Entity ${input.id} not found or not owned by this user.` });
  return JSON.stringify({ success: true, deleted_id: input.id });

} else {
  return 'Error: unknown action "' + action + '". Use: search, save, update, relate, graph, delete';
}
